const PwaInstallPrompt: React.FC = () => {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showPrompt, setShowPrompt] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [isStandalone, setIsStandalone] = useState(false);

  useEffect(() => {
    // Detect Standalone Mode
    const isInStandaloneMode = window.matchMedia('(display-mode: standalone)').matches || 
                               (window.navigator as any).standalone || 
                               document.referrer.includes('android-app://');

    setIsStandalone(isInStandaloneMode);
    if (isInStandaloneMode) return;

    // Detect iOS
    const userAgent = window.navigator.userAgent.toLowerCase();
    const isIosDevice = /iphone|ipad|ipod/.test(userAgent);
    setIsIOS(isIosDevice);

    // Check previous dismissal
    const isDismissed = localStorage.getItem('pwa_prompt_dismissed');

    // Android/Desktop Handler
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
      if (!isDismissed) {
        setShowPrompt(true);
      }
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // iOS Trigger (Show after short delay if not dismissed)
    if (isIosDevice && !isDismissed) {
      setTimeout(() => setShowPrompt(true), 3000);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const handleInstallClick = async () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') {
        setDeferredPrompt(null);
        setShowPrompt(false);
      }
    }
  };

  const handleDismiss = () => {
    setShowPrompt(false);
    localStorage.setItem('pwa_prompt_dismissed', 'true');
  };

  if (!showPrompt || isStandalone) return null;

  return (
    <AnimatePresence>
      {showPrompt && (
        <div className="fixed inset-0 z-[200] flex items-end sm:items-center justify-center pointer-events-none p-4 sm:p-6">
          <motion.div
            initial={{ y: 100, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 100, opacity: 0 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            className="w-full max-w-sm bg-app-bg/90 backdrop-blur-xl border border-app-border shadow-2xl p-6 rounded-2xl pointer-events-auto flex flex-col gap-6"
          >
            <div className="flex items-start justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-app-accent text-app-accent-text rounded-xl flex items-center justify-center font-black text-lg shadow-lg">
                  PP
                </div>
                <div>
                  <h3 className="text-sm font-black uppercase tracking-widest text-app-text">Profit Pips</h3>
                  <p className="text-[10px] text-app-muted font-bold">App-like Experience</p>
                </div>
              </div>
              <button onClick={handleDismiss} className="text-app-muted hover:text-app-text transition-colors p-1">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>

            <div className="space-y-2">
              <div className="flex items-center gap-3 text-xs text-app-muted">
                <i className="fa-solid fa-check text-green-500"></i>
                <span>Instant Access from Home Screen</span>
              </div>
              <div className="flex items-center gap-3 text-xs text-app-muted">
                <i className="fa-solid fa-check text-green-500"></i>
                <span>Full Screen Performance</span>
              </div>
              <div className="flex items-center gap-3 text-xs text-app-muted">
                <i className="fa-solid fa-check text-green-500"></i>
                <span>Offline Capabilities</span>
              </div>
            </div>

            {isIOS ? (
              <div className="bg-app-surface p-4 rounded-lg space-y-2 text-center">
                <p className="text-[10px] font-bold uppercase tracking-widest text-app-muted">To Install on iOS</p>
                <div className="text-xs font-medium flex items-center justify-center gap-1.5">
                  Tap <i className="fa-solid fa-share-from-square text-blue-500"></i> then <span className="font-bold">"Add to Home Screen"</span>
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-2 gap-3">
                <button 
                  onClick={handleDismiss}
                  className="py-3 border border-app-border rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-app-surface transition-colors"
                >
                  Later
                </button>
                <button 
                  onClick={handleInstallClick}
                  className="py-3 bg-app-accent text-app-accent-text rounded-lg text-[10px] font-black uppercase tracking-widest hover:opacity-90 shadow-lg transition-all"
                >
                  Install App
                </button>
              </div>
            )}
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

